                  </div>
                  <div className="p-8">
                    <RegistrationForm onSuccess={handleSuccess} />
                  </div>
                </div>
              </div>
            </section>
          </>
        ) : (
          <SubmissionSuccess id={submissionId} onReset={handleReset} />
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

